@code {
    /// <summary>The task/milestone this bar represents.</summary>
    [Parameter, EditorRequired] public GanttTask Task { get; set; } = null!;

    /// <summary>
    /// Left pixel offset within the timeline canvas, already resolved by the
    /// caller via <see cref="GanttScale.DateToPixel"/>. For a milestone this is
    /// the diamond's bounding-box left edge (center-column minus half the bar
    /// height), not the task's raw start-date pixel.
    /// </summary>
    [Parameter] public double X { get; set; }

    /// <summary>Pixel width of the bar (or, for a milestone, the diamond's square bounding box — equal to <see cref="BarHeight"/>).</summary>
    [Parameter] public double Width { get; set; }

    /// <summary>Zero-based row slot within the timeline (mirrors v2's rowSlot — may differ from the task's index when group header rows are interleaved by a future task).</summary>
    [Parameter] public int RowIndex { get; set; }

    /// <summary>Bar height in pixels. Defaults to <see cref="GanttScale.DefaultBarHeight"/>.</summary>
    [Parameter] public int BarHeight { get; set; } = GanttScale.DefaultBarHeight;

    /// <summary>
    /// Per-task colour override (hex, rgb, or a CSS variable reference) — mirrors
    /// v2's <c>BarColor</c> delegate output. Null falls back to the primary theme
    /// colour token.
    /// </summary>
    [Parameter] public string? Color { get; set; }

    /// <summary>Replaces the bar's default label content when set. Not used for milestones (v2 parity: milestones always show their name next to the diamond).</summary>
    [Parameter] public RenderFragment<GanttTask>? BarTemplate { get; set; }

    /// <summary>Additional CSS classes merged onto the positioned wrapper.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures unmatched attributes and applies them to the positioned wrapper.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Tooltip's own root div defaults to "relative inline-flex" (see Tooltip.razor);
    // Cx.Merge resolves the relative/absolute conflict group so "absolute" (added
    // here) wins over Tooltip's "relative" while "inline-flex" survives untouched.
    private string WrapperClass => Cx.Merge("absolute", Class);

    private string InnerClass => Task.IsMilestone
        ? "relative flex h-full w-full items-center justify-center"
        : "relative flex h-full w-full items-center overflow-hidden rounded";

    private string ResolvedColor => Color ?? "var(--color-primary)";

    private string ColorStyle => Task.IsMilestone
        ? FormattableString.Invariant($"background-color:{ResolvedColor};transform:rotate(45deg);")
        : FormattableString.Invariant($"background-color:{ResolvedColor};");

    private string ProgressStyle
    {
        get
        {
            var progress = Math.Clamp(Task.Progress, 0, 100);
            return FormattableString.Invariant($"width:{progress}%;background-color:{ResolvedColor};");
        }
    }

    // The wrapper carries BOTH the raw --lumeo-gantt-bar-* custom properties (so a
    // consumer stylesheet can read/override them) and the physical left/top/width/
    // height that consume them — see GanttScale's TZ/DST-safety note for why every
    // number here comes from plain arithmetic, never culture-sensitive formatting.
    private string WrapperStyle
    {
        get
        {
            var top = (RowIndex * GanttScale.RowHeight) + (GanttScale.RowHeight - BarHeight) / 2.0;
            return FormattableString.Invariant(
                $"--lumeo-gantt-bar-x:{X}px;--lumeo-gantt-bar-w:{Width}px;--lumeo-gantt-bar-row:{RowIndex};left:var(--lumeo-gantt-bar-x);top:{top}px;width:var(--lumeo-gantt-bar-w);height:{BarHeight}px;");
        }
    }

    private Dictionary<string, object> WrapperAttributes
    {
        get
        {
            var attrs = new Dictionary<string, object>
            {
                ["style"] = WrapperStyle,
                ["data-task-id"] = Task.Id,
            };
            if (Task.IsMilestone) attrs["data-milestone"] = "true";
            // Author-supplied attributes win on collision (splat-last semantics
            // used throughout Lumeo — see TooltipTrigger.BuildAttrs for the same pattern).
            if (AdditionalAttributes is not null)
                foreach (var kv in AdditionalAttributes) attrs[kv.Key] = kv.Value;
            return attrs;
        }
    }
}

