@code {
    /// <summary>The active zoom level. Two-way bindable via <see cref="ViewModeChanged"/>.</summary>
    [Parameter] public GanttViewMode ViewMode { get; set; } = GanttViewMode.Day;

    /// <summary>Raised when the user picks a new zoom level from the toolbar.</summary>
    [Parameter] public EventCallback<GanttViewMode> ViewModeChanged { get; set; }

    /// <summary>
    /// Restricts which zoom buttons render, in the given order. Null/empty shows
    /// the full default set (Day, Week, Month, Year) — mirrors v2's Gantt.razor
    /// ZoomLevels contract exactly, including the QuarterDay/HalfDay exclusion
    /// (no toolbar-representable label for either).
    /// </summary>
    [Parameter] public IReadOnlyList<GanttViewMode>? ZoomLevels { get; set; }

    /// <summary>The current period's title (e.g. "January 2026"), computed by whatever owns the GanttState's VisibleRange.</summary>
    [Parameter] public string? PeriodLabel { get; set; }

    /// <summary>Raised when Today is clicked — the owner recenters VisibleRange on today.</summary>
    [Parameter] public EventCallback OnToday { get; set; }

    /// <summary>Raised when the previous-period button is clicked — the owner shifts VisibleRange back by the view mode's step.</summary>
    [Parameter] public EventCallback OnPrevious { get; set; }

    /// <summary>Raised when the next-period button is clicked — the owner shifts VisibleRange forward by the view mode's step.</summary>
    [Parameter] public EventCallback OnNext { get; set; }

    /// <summary>Additional CSS classes merged onto the root toolbar element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures unmatched attributes and applies them to the root toolbar element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass => Cx.Merge("flex flex-wrap items-center justify-between gap-2", Class);

    private static readonly GanttViewMode[] DefaultZoomLevels =
    {
        GanttViewMode.Day, GanttViewMode.Week, GanttViewMode.Month, GanttViewMode.Year,
    };

    // Only the toolbar-representable levels, in canonical order — same precedent
    // as v2's Gantt.razor ResolvedZoomLevels.
    private IReadOnlyList<GanttViewMode> ResolvedZoomLevels =>
        ZoomLevels is { Count: > 0 }
            ? ZoomLevels.Where(l => Array.IndexOf(DefaultZoomLevels, l) >= 0).ToList()
            : DefaultZoomLevels;

    // Unselected (null) when ViewMode is QuarterDay/HalfDay or excluded by ZoomLevels
    // — same as v2's _toolbarViewValue.
    private string? ToolbarValue => ViewMode switch
    {
        GanttViewMode.Day => "Day",
        GanttViewMode.Week => "Week",
        GanttViewMode.Month => "Month",
        GanttViewMode.Year => "Year",
        _ => null,
    };

    private static string ZoomLabelKey(GanttViewMode level) => level switch
    {
        GanttViewMode.Day => "Gantt.Day",
        GanttViewMode.Week => "Gantt.Week",
        GanttViewMode.Month => "Gantt.Month",
        GanttViewMode.Year => "Gantt.Year",
        _ => "Gantt.Day",
    };

    private async Task HandleViewModeChangedAsync(string? v)
    {
        if (string.IsNullOrEmpty(v)) return;
        if (!Enum.TryParse<GanttViewMode>(v, out var parsed)) return;
        if (parsed == ViewMode) return;
        if (ViewModeChanged.HasDelegate) await ViewModeChanged.InvokeAsync(parsed);
    }

    private Task HandleTodayAsync(MouseEventArgs e) => OnToday.HasDelegate ? OnToday.InvokeAsync() : Task.CompletedTask;
    private Task HandlePreviousAsync(MouseEventArgs e) => OnPrevious.HasDelegate ? OnPrevious.InvokeAsync() : Task.CompletedTask;
    private Task HandleNextAsync(MouseEventArgs e) => OnNext.HasDelegate ? OnNext.InvokeAsync() : Task.CompletedTask;
}

namespace Lumeo.GanttV3;

/// <summary>
/// Whether a <see cref="GanttVisibleRow"/> represents a real task/milestone or
/// a synthetic flat-grouping section header.
///
/// <c>public</c> rather than <c>internal</c> (design spec asked for the row
/// model to stay internal, same as <c>GanttState</c>): unlike <c>GanttState</c>
/// — which is never exposed as a component parameter's type — <see cref="GanttVisibleRow"/>
/// (and therefore this enum, one of its members) crosses <c>GanttTree</c>/
/// <c>GanttTimeline</c>/<c>GanttArrowLayer</c>'s <c>Rows</c> parameters, and
/// those components are unavoidably <c>public</c> (the Razor compiler always
/// generates a component's class as <c>public partial class</c> — see
/// GanttBar.razor's own NOTE for the dotnet/aspnetcore#5516 /
/// dotnet/razor#8715 background). A <c>public</c> member can't expose a
/// less-accessible type (CS0053), so this — like <see cref="GanttVisibleRow"/> —
/// is <c>public</c> and recorded in PublicAPI.Unshipped.txt; flagged for the
/// reviewer/team lead to confirm, same as the earlier T2 components.
/// </summary>
public enum GanttRowKind
{
    /// <summary>A real <see cref="GanttTask"/> — either a root/leaf task (no hierarchy in play) or a hierarchy node (<see cref="GanttTask.ParentId"/> in play).</summary>
    Task,

    /// <summary>A synthetic placeholder row carrying only a group label — v2's group-header row (gantt-v2.js lines 428-449). Never has a <see cref="GanttVisibleRow.Task"/>.</summary>
    GroupHeader,
}

/// <summary>
/// One row slot in the combined tree-pane / timeline row list — the single,
/// shared source of truth for row ORDER and VISIBILITY that <c>GanttTree</c>,
/// <c>GanttTimeline</c>, and <c>GanttArrowLayer</c> all render against (design
/// spec Phase 2, T3: "row list is computed once in the root/shared code and fed
/// to both [panes]"). Its list POSITION is the row's slot index for
/// <see cref="GanttScale.BarTop"/>/<see cref="GanttScale.BarGeometry"/> purposes —
/// mirrors v2's <c>rowSlot</c> counter, which advances for group-header rows too
/// (gantt-v2.js lines 420-452).
/// </summary>
/// <param name="Kind">Task row or synthetic group-header row.</param>
/// <param name="Task">The underlying task/milestone. Null only for a <see cref="GanttRowKind.GroupHeader"/> row.</param>
/// <param name="Label">Display text — the task's <see cref="GanttTask.Name"/>, or the group's label for a header row.</param>
/// <param name="Depth">Indent depth for the tree pane. 0 for a root task or a group header; a hierarchy child is its parent's depth + 1; a task nested under a flat group header is depth 1 (see <see cref="GanttRowModel.BuildVisibleRows"/> remarks for why hierarchy and flat grouping are mutually exclusive per task list).</param>
/// <param name="HasChildren">True when this row is collapsible — a hierarchy parent (has at least one child task) or any group header (always collapsible: collapsing it hides its member rows).</param>
/// <param name="ToggleKey">The key to pass to <see cref="GanttState.ToggleCollapsed"/>/<see cref="GanttState.SetCollapsed"/> to collapse/expand this row. Null when <see cref="HasChildren"/> is false (nothing to toggle). A task-hierarchy row's key is its own <see cref="GanttTask.Id"/>; a group header's key is <see cref="GanttRowModel.GroupToggleKey"/> of its label (a distinct namespace so a task id can never collide with a group key).</param>
/// <param name="IsCollapsed">Whether this row is CURRENTLY collapsed (its descendants/members are excluded from the row list this row appears in) — resolved once here so callers never re-query <c>GanttState.Collapsed</c> themselves.</param>
/// <remarks>
/// <c>public</c> rather than <c>internal</c> — see <see cref="GanttRowKind"/>'s
/// remarks for why: this type crosses public component parameter boundaries
/// (<c>GanttTree.Rows</c>, <c>GanttTimeline.Rows</c>, <c>GanttArrowLayer.Rows</c>),
/// so it can't stay internal (CS0053). Recorded in PublicAPI.Unshipped.txt;
/// flagged for the reviewer/team lead to confirm, same precedent as GanttBar/
/// GanttNav/Gantt3/GanttTimeline in T2.
/// </remarks>
public readonly record struct GanttVisibleRow(
    GanttRowKind Kind,
    GanttTask? Task,
    string Label,
    int Depth,
    bool HasChildren,
    string? ToggleKey,
    bool IsCollapsed);

/// <summary>
/// Pure, static row-flattening logic for the GanttV3 tree pane + timeline
/// (design spec Phase 2, T3). Turns <see cref="GanttState.Tasks"/> +
/// <see cref="GanttState.Collapsed"/> into the single ordered, already-filtered
/// <see cref="GanttVisibleRow"/> list both panes render — see
/// <see cref="GanttVisibleRow"/>'s own remarks for why that sharing matters.
/// No Blazor/DOM dependency, so it is unit-testable in isolation (mirrors how
/// <see cref="GanttScale"/> and <see cref="GanttState"/> were built in earlier
/// tasks).
/// </summary>
internal static class GanttRowModel
{
    /// <summary>
    /// Prefix applied to a flat group's label to derive its <see cref="GanttState"/>
    /// collapse key — <see cref="GanttState.Collapsed"/> is a single
    /// <c>HashSet&lt;string&gt;</c> shared by both hierarchy task ids and flat group
    /// labels, so this prefix keeps the two key namespaces from ever colliding
    /// (a task whose id happens to equal some other task's group label, however
    /// unlikely, must not accidentally collapse the wrong thing).
    /// </summary>
    private const string GroupKeyPrefix = "group::";

    /// <summary>The <see cref="GanttState.Collapsed"/> key for the flat group named <paramref name="groupLabel"/>.</summary>
    internal static string GroupToggleKey(string groupLabel) => GroupKeyPrefix + groupLabel;

    /// <summary>True when at least one task in the list sets <see cref="GanttTask.ParentId"/> — the signal that hierarchy mode (not flat <see cref="GanttTask.GroupLabel"/> grouping) governs row order.</summary>
    internal static bool UsesHierarchy(IReadOnlyList<GanttTask> tasks)
    {
        for (var i = 0; i < tasks.Count; i++)
            if (tasks[i].ParentId is not null) return true;
        return false;
    }

    /// <summary>
    /// The default for <c>Gantt3.ShowTreePane</c> when the caller doesn't set it
    /// explicitly (design spec: "default: true when GroupBy set or any task has
    /// ParentId, else false"). <paramref name="groupBySet"/> is whether the
    /// caller's <c>GroupBy</c> delegate parameter is non-null — a parameter the
    /// component itself owns, so it's passed in rather than re-derived here.
    /// </summary>
    internal static bool DefaultShowTreePane(IReadOnlyList<GanttTask> tasks, bool groupBySet) =>
        groupBySet || UsesHierarchy(tasks);

    /// <summary>
    /// Flattens <paramref name="tasks"/> into the ordered, collapse-filtered row
    /// list both panes render. Hierarchy (<see cref="GanttTask.ParentId"/>) takes
    /// priority over flat <see cref="GanttTask.GroupLabel"/> grouping whenever any
    /// task in the list sets a <see cref="GanttTask.ParentId"/> — the two are
    /// mutually exclusive per task list (see <see cref="BuildFlatGroupRows"/>'s
    /// remarks for why v2's <c>GroupLabel</c> field, not the <c>GroupBy</c> sort
    /// delegate, is what actually drives header rows).
    /// </summary>
    internal static IReadOnlyList<GanttVisibleRow> BuildVisibleRows(IReadOnlyList<GanttTask> tasks, IReadOnlySet<string> collapsed) =>
        UsesHierarchy(tasks) ? BuildHierarchyRows(tasks, collapsed) : BuildFlatGroupRows(tasks, collapsed);

    // ── ParentId hierarchy ───────────────────────────────────────────────────

    private static List<GanttVisibleRow> BuildHierarchyRows(IReadOnlyList<GanttTask> tasks, IReadOnlySet<string> collapsed)
    {
        // Bucket every NON-root task by its (non-null) ParentId — Dictionary<TKey,_>
        // requires TKey : notnull, so root tasks (ParentId == null) are collected
        // into their own `roots` list instead of a null-keyed bucket. Both
        // preserve the caller's original relative order — a sibling's position
        // among its siblings is whatever order the caller's Tasks list already
        // has them in (Gantt3 has already applied GroupBy sorting, if any,
        // before this runs).
        var childrenByParentId = new Dictionary<string, List<GanttTask>>();
        var roots = new List<GanttTask>();
        var taskById = new Dictionary<string, GanttTask>(tasks.Count);
        foreach (var t in tasks)
        {
            taskById[t.Id] = t; // last-wins on a duplicate id — out-of-scope invalid input, just don't throw
            if (t.ParentId is null) { roots.Add(t); continue; }
            if (!childrenByParentId.TryGetValue(t.ParentId, out var siblings))
                childrenByParentId[t.ParentId] = siblings = new List<GanttTask>();
            siblings.Add(t);
        }

        var rows = new List<GanttVisibleRow>(tasks.Count);
        var visited = new HashSet<string>();

        void Walk(IReadOnlyList<GanttTask> siblings, int depth)
        {
            foreach (var task in siblings)
            {
                // Defends against a cyclic ParentId graph (A's parent is B, B's
                // parent is A — invalid input, but must not stack-overflow):
                // a task already rendered once is never re-walked as someone
                // else's child.
                if (visited.Contains(task.Id)) continue;
                var hasChildren = childrenByParentId.TryGetValue(task.Id, out var children);
                var isCollapsed = collapsed.Contains(task.Id);
                rows.Add(new GanttVisibleRow(GanttRowKind.Task, task, task.Name, depth, hasChildren, hasChildren ? task.Id : null, isCollapsed));
                visited.Add(task.Id);
                if (hasChildren && !isCollapsed) Walk(children!, depth + 1);
            }
        }

        Walk(roots, 0);

        // Orphans: a task whose ParentId points at an id that never appears as
        // ANY task's Id in this list at all (deleted/typo'd parent, or a partial
        // page of a larger tree) is rendered at root depth rather than silently
        // dropped. Gated on "does this parentId correspond to a real task",
        // NOT on "was it visited" — a real parent that's simply nested under a
        // collapsed ancestor is correctly still unvisited, and its children
        // must stay hidden too, not be promoted to fake roots.
        var allTaskIds = new HashSet<string>(tasks.Count);
        foreach (var t in tasks) allTaskIds.Add(t.Id);

        foreach (var (parentId, orphanSiblings) in childrenByParentId)
        {
            if (allTaskIds.Contains(parentId)) continue; // real parent task — reachable (or intentionally collapsed-hidden) via the walk above
            Walk(orphanSiblings, 0);
        }

        // A task can still be unvisited at this point for TWO different reasons,
        // which must NOT be handled the same way:
        //   1. It's a legitimate descendant of a COLLAPSED ancestor (Walk added
        //      the ancestor's row but deliberately did not recurse into it) —
        //      still correctly hidden, must NOT be promoted.
        //   2. It sits on a cyclic ParentId chain (A's parent is B, B's parent
        //      is A — or a self-loop, A's parent is A) that no root/orphan walk
        //      above could ever reach — genuinely invalid input, but silently
        //      dropping those rows is worse than rendering them somewhere
        //      deterministic (reviewer-verified without any safety net:
        //      [A(parent:B), B(parent:A), D] rendered only D — A/B vanished —
        //      and [A(parent:A)] rendered 0 rows).
        // IsHiddenByCollapsedAncestor distinguishes the two by chasing the
        // ParentId chain upward: if it ever reaches a task already in `visited`,
        // that ancestor WAS rendered (case 1 — collapse suppressed recursion
        // past it) and this task must stay hidden. If instead the chain loops
        // back on itself (a real GanttTask id repeats within this single
        // upward walk) without ever touching `visited`, there is no rendered
        // ancestor to hide behind — it's case 2, a genuine cycle, and safe to
        // promote.
        bool IsHiddenByCollapsedAncestor(GanttTask start)
        {
            var seenInThisChain = new HashSet<string> { start.Id };
            var parentId = start.ParentId;
            while (parentId is not null)
            {
                if (visited.Contains(parentId)) return true;
                if (!seenInThisChain.Add(parentId)) return false; // looped back within this chain -> a cycle, not a collapsed ancestor
                if (!taskById.TryGetValue(parentId, out var parentTask)) return false; // dangling reference already handled by the orphan pass above
                parentId = parentTask.ParentId;
            }
            return false; // chain reached a real root (null ParentId) without ever being visited — the root walk above always covers this first, so this is unreachable in practice
        }

        // Cycle safety net: walk `tasks` in original order and promote the
        // first still-unvisited, not-collapse-hidden member of each remaining
        // cycle to a root (depth 0) — breaks the cycle at a stable, input-order
        // point. Walk's own `visited` guard (above) stops it from re-entering
        // the loop it just broke out of, so any other member of the SAME cycle
        // reachable as that root's "child" renders once, at depth 1+, instead
        // of being re-promoted to its own fake root.
        foreach (var t in tasks)
        {
            if (visited.Contains(t.Id)) continue;
            if (IsHiddenByCollapsedAncestor(t)) continue;
            Walk(new[] { t }, 0);
        }

        return rows;
    }

    // ── Flat GroupLabel grouping (v2 parity) ────────────────────────────────

    /// <summary>
    /// Faithful port of v2's group-header interleaving (gantt-v2.js lines
    /// 420-452: <c>tasks.forEach</c> with the <c>lastGroupLabel</c> transition
    /// check). Note this reads <see cref="GanttTask.GroupLabel"/> — the field a
    /// consumer sets directly on each task — NOT the <c>Gantt3.GroupBy</c>
    /// delegate parameter; v2 never threads <c>GroupBy</c>'s output into the JS
    /// renderer at all, only the sort order it produces (<c>Gantt.razor</c>'s
    /// <c>SortedTasks</c>, and <c>Gantt3</c>'s own copy of the same method) —
    /// the JS side only ever sees <c>task.group_label</c> (<c>ToJsTask</c>'s
    /// <c>t.GroupLabel</c>). This port keeps that exact split: by the time this
    /// method runs, <paramref name="tasks"/> is already GroupBy-sorted (Gantt3's
    /// job), and header rows are driven purely by consecutive-run detection on
    /// <see cref="GanttTask.GroupLabel"/>, same as v2.
    /// </summary>
    private static List<GanttVisibleRow> BuildFlatGroupRows(IReadOnlyList<GanttTask> tasks, IReadOnlySet<string> collapsed)
    {
        var rows = new List<GanttVisibleRow>(tasks.Count);
        string? lastGroupLabel = null;
        var hidingCurrentGroup = false;

        foreach (var task in tasks)
        {
            if (task.GroupLabel is not null && task.GroupLabel != lastGroupLabel)
            {
                lastGroupLabel = task.GroupLabel;
                var key = GroupToggleKey(task.GroupLabel);
                hidingCurrentGroup = collapsed.Contains(key);
                rows.Add(new GanttVisibleRow(GanttRowKind.GroupHeader, null, task.GroupLabel, 0, true, key, hidingCurrentGroup));
            }

            if (hidingCurrentGroup) continue;

            // A task under a group header is indented one level; an ungrouped
            // task (no GroupLabel at all) sits at depth 0 like a hierarchy root.
            var depth = task.GroupLabel is not null ? 1 : 0;
            rows.Add(new GanttVisibleRow(GanttRowKind.Task, task, task.Name, depth, false, null, false));
        }

        return rows;
    }
}

using System.Globalization;

namespace Lumeo.GanttV3;

/// <summary>
/// The unit of a <see cref="GanttViewMode"/>'s date grid columns. Mirrors the
/// <c>unit</c> field of gantt-v2.js's <c>VIEW_MODES</c> table
/// (wwwroot/js/gantt-v2.js, lines 29-36).
/// </summary>
internal enum GanttScaleUnit
{
    Hour,
    Day,
    Month,
    Year,
}

/// <summary>
/// The upper (grouping) header row's label kind. Mirrors the
/// <c>headerFmt.upper</c> values in gantt-v2.js's <c>VIEW_MODES</c> table and the
/// <c>switch (cfg.headerFmt.upper)</c> in <c>render()</c> (gantt-v2.js lines 386-392).
/// <see cref="None"/> mirrors the empty-string upper format used by
/// <see cref="GanttViewMode.Year"/>, which renders no upper row at all — v2's
/// <c>if (upperText &amp;&amp; ...)</c> guard treats an empty string as falsy and skips it.
/// </summary>
internal enum GanttHeaderUpperKind
{
    /// <summary>No upper row (v2 <c>headerFmt.upper: ''</c>, <see cref="GanttViewMode.Year"/>).</summary>
    None,
    /// <summary>Full month name, e.g. "January" (v2 <c>'month'</c> -&gt; <c>fmtMonth</c>).</summary>
    Month,
    /// <summary>4-digit year, e.g. "2026" (v2 <c>'year'</c> -&gt; <c>fmtYear</c>).</summary>
    Year,
    /// <summary>"{month} {day}", e.g. "January 5" (v2 <c>'day'</c> -&gt; <c>`${fmtMonth(d)} ${d.getDate()}`</c>).</summary>
    Day,
}

/// <summary>
/// The lower (per-column) header row's label kind. Mirrors the
/// <c>headerFmt.lower</c> values in gantt-v2.js's <c>VIEW_MODES</c> table and the
/// <c>switch (cfg.headerFmt.lower)</c> in <c>render()</c> (gantt-v2.js lines 366-375).
/// </summary>
internal enum GanttHeaderLowerKind
{
    /// <summary>2-digit day-of-month, e.g. "05" (v2 <c>fmtDayNum</c>).</summary>
    DayNum,
    /// <summary>"{day}/{month}" (no leading zeros), e.g. "5/1" (v2 <c>`${d.getDate()}/${d.getMonth() + 1}`</c>).</summary>
    WeekRange,
    /// <summary>Short month name, e.g. "Jan" (v2 <c>fmtMonthShort</c>).</summary>
    MonthName,
    /// <summary>4-digit year, e.g. "2026" (v2 <c>fmtYear</c>).</summary>
    YearNum,
    /// <summary>"{hour}:00", 6-hour columns (v2 <c>time6h</c> — same rendering as <see cref="Time12h"/>).</summary>
    Time6h,
    /// <summary>"{hour}:00", 12-hour columns (v2 <c>time12h</c> — same rendering as <see cref="Time6h"/>).</summary>
    Time12h,
}

/// <summary>
/// Per-<see cref="GanttViewMode"/> scale configuration: column width, snap unit/step,
/// window padding, and the two header rows' label kinds. Value type mirroring one row
/// of gantt-v2.js's <c>VIEW_MODES</c> table (wwwroot/js/gantt-v2.js, lines 29-36) —
/// see <see cref="GanttScale.ViewModes"/> for the exact port of that table.
/// </summary>
internal readonly record struct GanttScaleConfig(
    int ColumnWidth,
    GanttScaleUnit Unit,
    int Step,
    int PadBefore,
    int PadAfter,
    GanttHeaderUpperKind HeaderUpper,
    GanttHeaderLowerKind HeaderLower);

/// <summary>
/// One run of identical, consecutive upper-row labels — e.g. every "Day" column
/// that falls in January collapses into a single "January" run spanning those
/// columns, instead of repeating the label per column. Mirrors v2's
/// <c>lastUpperLabel</c> de-duplication in <c>render()</c>'s header-label loop
/// (gantt-v2.js lines 351-404: <c>if (upperText &amp;&amp; upperText !== lastUpperLabel)</c>).
/// </summary>
/// <param name="StartIndex">Index into the date-units array (see <see cref="GanttScale.BuildDateUnits"/>) where the run starts.</param>
/// <param name="Span">Number of consecutive columns the run covers.</param>
/// <param name="Label">The upper-row text shared by every column in the run.</param>
internal readonly record struct GanttHeaderRun(int StartIndex, int Span, string Label);

/// <summary>
/// Pure, static date/pixel math for the Gantt v3 timeline — the behavioral
/// source is gantt-v2.js's <c>VIEW_MODES</c> table plus the <c>render()</c>
/// date-unit generation (lines 166-190), <c>dateToX</c>/<c>xToDate</c> closures
/// (lines 209-256), and the standalone <c>pixelsPerDay()</c> helper (lines
/// 727-734) used to snap drag deltas. Every method here is a faithful C# port
/// of that JS math — no Blazor/JS-interop dependency, so it is unit-testable
/// (and reusable by the v3 render tree, drag math, and parity harness) without
/// a browser.
///
/// TZ/DST safety: every method below operates purely on the <see cref="DateTime"/>
/// values it is given via calendar arithmetic (<c>AddHours</c>/<c>AddDays</c>/
/// <c>AddMonths</c>/<c>AddYears</c>) and calendar-field reads (<c>Year</c>/<c>Month</c>/
/// <c>Day</c>/<c>Hour</c>). None of it ever calls <c>ToLocalTime</c>, <c>ToUniversalTime</c>,
/// or touches <see cref="TimeZoneInfo"/> — so <see cref="DateTime.Kind"/> is irrelevant
/// to the results and no local-timezone DST transition (spring-forward/fall-back) can
/// perturb the math, unlike JS's <c>Date</c> arithmetic (v2's <c>addDays</c>/<c>addMonths</c>
/// construct calendar dates via the local-timezone-aware <c>Date</c> constructor and
/// setters). Callers/tests should still prefer <see cref="DateTimeKind.Utc"/>
/// consistently — not because the math needs it, but so a stray <c>ToLocalTime()</c>
/// introduced later would visibly change values instead of silently matching by
/// accident on a UTC-configured CI box.
/// </summary>
internal static class GanttScale
{
    /// <summary>Row height in pixels for a single task row. Mirrors v2's <c>ROW_HEIGHT</c> (gantt-v2.js line 38).</summary>
    internal const int RowHeight = 36;

    /// <summary>Default task-bar height in pixels. Mirrors v2's <c>DEFAULT_BAR_HEIGHT</c> (gantt-v2.js line 39).</summary>
    internal const int DefaultBarHeight = 22;

    /// <summary>Header block height in pixels (both rows combined). Mirrors v2's <c>HEADER_HEIGHT</c> (gantt-v2.js line 40).</summary>
    internal const int HeaderHeight = 56;

    /// <summary>
    /// Faithful port of gantt-v2.js's <c>VIEW_MODES</c> table (lines 29-36). Every
    /// field below is copied verbatim from the corresponding JS literal; see each
    /// <see cref="GanttScaleUnit"/>/<see cref="GanttHeaderUpperKind"/>/<see cref="GanttHeaderLowerKind"/>
    /// member for the v2 string it replaces.
    /// </summary>
    internal static readonly IReadOnlyDictionary<GanttViewMode, GanttScaleConfig> ViewModes =
        new Dictionary<GanttViewMode, GanttScaleConfig>
        {
            // QuarterDay: { columnWidth: 38, unit: 'hour', step: 6,  padBefore: 24, padAfter: 24, headerFmt: { upper: 'day',   lower: 'time6h' } },
            [GanttViewMode.QuarterDay] = new GanttScaleConfig(38, GanttScaleUnit.Hour, 6, 24, 24, GanttHeaderUpperKind.Day, GanttHeaderLowerKind.Time6h),
            // HalfDay:    { columnWidth: 38, unit: 'hour', step: 12, padBefore: 24, padAfter: 24, headerFmt: { upper: 'day',   lower: 'time12h' } },
            [GanttViewMode.HalfDay] = new GanttScaleConfig(38, GanttScaleUnit.Hour, 12, 24, 24, GanttHeaderUpperKind.Day, GanttHeaderLowerKind.Time12h),
            // Day:        { columnWidth: 38, unit: 'day',  step: 1,  padBefore: 60, padAfter: 60, headerFmt: { upper: 'month', lower: 'dayNum' } },
            [GanttViewMode.Day] = new GanttScaleConfig(38, GanttScaleUnit.Day, 1, 60, 60, GanttHeaderUpperKind.Month, GanttHeaderLowerKind.DayNum),
            // Week:       { columnWidth: 140, unit: 'day', step: 7,  padBefore: 16, padAfter: 16, headerFmt: { upper: 'month', lower: 'weekRange' } },
            [GanttViewMode.Week] = new GanttScaleConfig(140, GanttScaleUnit.Day, 7, 16, 16, GanttHeaderUpperKind.Month, GanttHeaderLowerKind.WeekRange),
            // Month:      { columnWidth: 120, unit: 'month', step: 1, padBefore: 12, padAfter: 12, headerFmt: { upper: 'year', lower: 'monthName' } },
            [GanttViewMode.Month] = new GanttScaleConfig(120, GanttScaleUnit.Month, 1, 12, 12, GanttHeaderUpperKind.Year, GanttHeaderLowerKind.MonthName),
            // Year:       { columnWidth: 120, unit: 'year', step: 1, padBefore: 4,  padAfter: 6,  headerFmt: { upper: '',     lower: 'yearNum' } },
            [GanttViewMode.Year] = new GanttScaleConfig(120, GanttScaleUnit.Year, 1, 4, 6, GanttHeaderUpperKind.None, GanttHeaderLowerKind.YearNum),
        };

    /// <summary>Looks up the <see cref="GanttScaleConfig"/> for a view mode.</summary>
    internal static GanttScaleConfig GetConfig(GanttViewMode mode) => ViewModes[mode];

    /// <summary>
    /// Builds the list of column-start dates covering <paramref name="rangeStart"/>..<paramref name="rangeEnd"/>
    /// (inclusive of both ends where the unit's step lands on them), one entry per
    /// rendered timeline column. Faithful port of the per-unit date-unit generation
    /// in v2's <c>render()</c> (gantt-v2.js lines 166-190) — <paramref name="rangeStart"/>/
    /// <paramref name="rangeEnd"/> here correspond to v2's already-padded
    /// <c>startDate</c>/<c>endDate</c> locals (padding itself is the windowing caller's
    /// concern — GanttState/GanttTimeline in later tasks — not this pure helper's).
    /// </summary>
    internal static IReadOnlyList<DateTime> BuildDateUnits(GanttViewMode mode, DateTime rangeStart, DateTime rangeEnd)
    {
        var cfg = GetConfig(mode);
        var units = new List<DateTime>();

        switch (cfg.Unit)
        {
            case GanttScaleUnit.Day:
            {
                // totalDays = dayDiff(startDate, endDate) + 1; totalColumns = ceil(totalDays / step)
                var totalDays = (int)Math.Round((rangeEnd - rangeStart).TotalDays) + 1;
                var totalColumns = (int)Math.Ceiling(totalDays / (double)cfg.Step);
                for (var i = 0; i < totalColumns; i++)
                    units.Add(rangeStart.AddDays(i * cfg.Step));
                break;
            }
            case GanttScaleUnit.Month:
            {
                // for (let d = startDate; d <= endDate; d = addMonths(d, 1))
                // v2 hardcodes +1 here (gantt-v2.js:176) rather than reading cfg.step —
                // Month is the only mode using this unit and its VIEW_MODES step is 1,
                // so `cfg.Step` and the literal 1 are equivalent today. Using cfg.Step
                // instead of a hardcoded 1 is a deliberate generalization (keeps this
                // branch correct if a future step-2+ month mode is ever added) that
                // stays byte-identical to v2 for every currently-shipped view mode.
                for (var d = rangeStart; d <= rangeEnd; d = d.AddMonths(cfg.Step))
                    units.Add(d);
                break;
            }
            case GanttScaleUnit.Year:
            {
                // for (let y = startYear; y <= endYear; y++) dateUnits.push(new Date(y, 0, 1));
                // v2 hardcodes +1 here too (gantt-v2.js:180) — same note as the Month
                // branch above: Year's VIEW_MODES step is 1, so cfg.Step === 1 today.
                for (var y = rangeStart.Year; y <= rangeEnd.Year; y += cfg.Step)
                    units.Add(new DateTime(y, 1, 1, 0, 0, 0, rangeStart.Kind));
                break;
            }
            case GanttScaleUnit.Hour:
            {
                // const totalHours = (endDate - startDate) / 3_600_000; for (i = 0; i < totalHours; i += step)
                var totalHours = (rangeEnd - rangeStart).TotalHours;
                for (var i = 0.0; i < totalHours; i += cfg.Step)
                    units.Add(rangeStart.AddHours(i));
                break;
            }
        }

        return units;
    }

    /// <summary>
    /// Maps a date to its pixel X offset relative to <paramref name="origin"/> (the
    /// first date unit — v2's <c>dateUnits[0]</c>). Faithful port of v2's <c>dateToX</c>
    /// closure (gantt-v2.js lines 209-230).
    /// </summary>
    internal static double DateToPixel(GanttViewMode mode, DateTime origin, DateTime date)
    {
        var cfg = GetConfig(mode);
        return cfg.Unit switch
        {
            // if (cfg.unit === 'day') { const days = dayDiff(dateUnits[0], d); return (days / cfg.step) * colW; }
            GanttScaleUnit.Day => ((date.Date - origin.Date).TotalDays / cfg.Step) * cfg.ColumnWidth,
            // if (cfg.unit === 'month') { months = (d.Year-o.Year)*12 + (d.Month-o.Month); dayFraction = (d.getDate()-1)/30; return (months+dayFraction)*colW; }
            GanttScaleUnit.Month => (((date.Year - origin.Year) * 12 + (date.Month - origin.Month)) + (date.Day - 1) / 30.0) * cfg.ColumnWidth,
            // if (cfg.unit === 'year') { years = d.Year-o.Year; dayFraction = (d.getMonth()*30 + d.getDate())/365; return (years+dayFraction)*colW; }
            GanttScaleUnit.Year => ((date.Year - origin.Year) + ((date.Month - 1) * 30 + date.Day) / 365.0) * cfg.ColumnWidth,
            // if (cfg.unit === 'hour') { hours = (d - dateUnits[0]) / 3_600_000; return (hours / cfg.step) * colW; }
            GanttScaleUnit.Hour => ((date - origin).TotalHours / cfg.Step) * cfg.ColumnWidth,
            _ => 0,
        };
    }

    /// <summary>
    /// Maps a pixel X offset (relative to <paramref name="origin"/>) back to a date.
    /// Faithful port of v2's <c>xToDate</c> closure (gantt-v2.js lines 232-252).
    /// Rounds to the nearest whole unit exactly as v2's <c>Math.round</c> does. JS
    /// <c>Math.round</c> rounds an exact half-integer tie toward POSITIVE infinity
    /// (<c>Math.round(-0.5) === -0</c>, <c>Math.round(-2.5) === -2</c>) — NOT away from
    /// zero (that would give -1/-3 for those two examples). <see cref="RoundToInt"/>
    /// mirrors that exact tie-breaking direction; see its own comment for the
    /// implementation. Ties matter here whenever a drag lands on an exact half-column
    /// pixel offset (e.g. Day mode, -19px = half of a 38px column).
    /// </summary>
    internal static DateTime PixelToDate(GanttViewMode mode, DateTime origin, double pixel)
    {
        var cfg = GetConfig(mode);
        return cfg.Unit switch
        {
            // if (cfg.unit === 'day') { days = Math.round((x/colW)*step); return addDays(dateUnits[0], days); }
            GanttScaleUnit.Day => origin.AddDays(RoundToInt((pixel / cfg.ColumnWidth) * cfg.Step)),
            // if (cfg.unit === 'month') { months = Math.round(x/colW); return addMonths(dateUnits[0], months); }
            GanttScaleUnit.Month => origin.AddMonths(RoundToInt(pixel / cfg.ColumnWidth)),
            // if (cfg.unit === 'year') { years = Math.round(x/colW); return new Date(dateUnits[0].getFullYear()+years, 0, 1); }
            GanttScaleUnit.Year => new DateTime(origin.Year + RoundToInt(pixel / cfg.ColumnWidth), 1, 1, 0, 0, 0, origin.Kind),
            // if (cfg.unit === 'hour') { hours = Math.round((x/colW)*step); d.setHours(d.getHours()+hours); return d; }
            GanttScaleUnit.Hour => origin.AddHours(RoundToInt((pixel / cfg.ColumnWidth) * cfg.Step)),
            _ => origin,
        };
    }

    /// <summary>
    /// Rounds like JS <c>Math.round</c>: half-integer ties round toward POSITIVE
    /// infinity (<c>Math.round(-0.5) === -0</c>, <c>Math.round(2.5) === 3</c>,
    /// <c>Math.round(-2.5) === -2</c>) — .NET's <see cref="Math.Round(double, MidpointRounding)"/>
    /// with <see cref="MidpointRounding.AwayFromZero"/> instead rounds ties away from
    /// zero (would give -1/-3 for the negative examples above), which silently
    /// diverges from v2 at exact half-column pixel offsets (battle-tested review
    /// finding: Day mode, pixel -19 — half of a 38px column — landed one day earlier
    /// in v3 than v2). <c>Math.Floor(value + 0.5)</c> reproduces the JS behavior
    /// exactly: adding 0.5 turns every tie into an exact integer that Floor then
    /// resolves toward positive infinity, same as Math.round's tie-break. Doubles
    /// have 52 bits of mantissa (~15-17 significant decimal digits); the pixel
    /// magnitudes this method ever sees (single/low-double-digit thousands, per the
    /// windowed-range design) are nowhere near where +0.5 could lose precision, so
    /// there is no large-magnitude edge case to worry about here.
    /// </summary>
    private static int RoundToInt(double value) => (int)Math.Floor(value + 0.5);

    /// <summary>
    /// Pixels-per-calendar-day for the given view mode — used to snap a raw drag
    /// pixel delta to whole-day increments regardless of column granularity (e.g.
    /// Week's 140px columns represent 7 days, so 1 day = 20px). Faithful port of
    /// v2's standalone <c>pixelsPerDay()</c> helper (gantt-v2.js lines 727-734),
    /// used by <c>commitDrag</c> to convert a mouse-move delta into whole days.
    /// </summary>
    internal static double PixelsPerDay(GanttViewMode mode)
    {
        var cfg = GetConfig(mode);
        return cfg.Unit switch
        {
            GanttScaleUnit.Day => cfg.ColumnWidth / (double)cfg.Step,       // Day:1, Week:20
            GanttScaleUnit.Hour => (cfg.ColumnWidth * 24.0) / cfg.Step,
            GanttScaleUnit.Month => cfg.ColumnWidth / 30.0,
            GanttScaleUnit.Year => cfg.ColumnWidth / 365.0,
            _ => cfg.ColumnWidth,
        };
    }

    /// <summary>
    /// Top pixel offset (relative to the row canvas, i.e. below the header) of a
    /// bar rendered in row slot <paramref name="rowIndex"/> at the given
    /// <paramref name="barHeight"/> — the bar is vertically centered within its
    /// <see cref="RowHeight"/>-tall row. Faithful port of the inline computation
    /// duplicated across v2's regular-bar and milestone branches (gantt-v2.js:
    /// <c>const barY = rowY + (ROW_HEIGHT - BAR_HEIGHT) / 2;</c>, line 455, where
    /// <c>rowY = HEADER_HEIGHT + idx * ROW_HEIGHT</c>, line 454 — the
    /// <c>HEADER_HEIGHT</c> term is the row CANVAS's own top offset, added by the
    /// caller when it positions the canvas itself, not by this helper). Hoisted
    /// out of GanttBar.razor's own <c>WrapperStyle</c> (T2) so <c>GanttArrowRouting</c>
    /// (T3) can recover the exact same bar-center Y a rendered <c>GanttBar</c> uses,
    /// without a second, potentially-diverging copy of the formula.
    /// </summary>
    internal static double BarTop(int rowIndex, int barHeight) =>
        (rowIndex * RowHeight) + (RowHeight - barHeight) / 2.0;

    /// <summary>
    /// Left pixel offset and width of a task's bar (or, for a milestone, its
    /// diamond's square bounding box) within the timeline canvas. Faithful port
    /// of v2's per-task geometry: milestone branch <c>cx = dateToX(task.start) +
    /// colW/2; half = BAR_HEIGHT/2</c> (gantt-v2.js lines 461-463, bounding-box
    /// left edge <c>cx - half</c>); regular-bar branch <c>x1 = dateToX(task.start);
    /// x2 = dateToX(addDays(task.end, 1)); barW = max(8, x2 - x1)</c> (gantt-v2.js
    /// lines 508-510 — the end-date's +1 day makes an inclusive end date render
    /// as a full day-wide segment rather than a zero-width sliver). Hoisted out of
    /// GanttTimeline.razor's own <c>RowItems</c> (T2) so <c>GanttArrowLayer</c> (T3)
    /// computes dependency-arrow endpoints from the IDENTICAL geometry a rendered
    /// <c>GanttBar</c> occupies — one shared formula, not two copies that could
    /// silently drift apart. <paramref name="columnWidth"/> is used only for the
    /// milestone center-of-column offset, matching what <c>GanttTimeline</c>
    /// already passes as its own <c>EffectiveColumnWidth</c> (the view mode's
    /// column width, or the caller's override) — <see cref="DateToPixel"/> itself
    /// always scales by the view mode's OWN column width regardless of that
    /// override (a pre-existing T2 behavior, out of scope for this task to change;
    /// sharing this helper keeps arrows and bars equally affected by it instead of
    /// only one of them being "correct").
    /// </summary>
    internal static (double X, double Width) BarGeometry(GanttTask task, GanttViewMode mode, DateTime origin, int columnWidth, int barHeight)
    {
        if (task.IsMilestone)
        {
            var center = DateToPixel(mode, origin, task.Start) + columnWidth / 2.0;
            var half = barHeight / 2.0;
            return (center - half, barHeight);
        }

        var x1 = DateToPixel(mode, origin, task.Start);
        var x2 = DateToPixel(mode, origin, task.End.AddDays(1));
        return (x1, Math.Max(8, x2 - x1));
    }

    /// <summary>
    /// The lower (per-column) header row's label for every date unit, in order.
    /// Faithful port of the <c>switch (cfg.headerFmt.lower)</c> block in v2's
    /// <c>render()</c> (gantt-v2.js lines 366-375).
    /// </summary>
    internal static IReadOnlyList<string> LowerLabels(GanttViewMode mode, IReadOnlyList<DateTime> units)
    {
        var cfg = GetConfig(mode);
        var labels = new string[units.Count];
        for (var i = 0; i < units.Count; i++)
            labels[i] = LowerLabel(cfg.HeaderLower, units[i]);
        return labels;
    }

    private static string LowerLabel(GanttHeaderLowerKind kind, DateTime d) => kind switch
    {
        // case 'dayNum': lowerText = fmtDayNum(d); -> String(d.getDate()).padStart(2, '0')
        GanttHeaderLowerKind.DayNum => d.Day.ToString("D2", CultureInfo.InvariantCulture),
        // case 'weekRange': lowerText = `${d.getDate()}/${d.getMonth() + 1}`;
        GanttHeaderLowerKind.WeekRange => $"{d.Day}/{d.Month}",
        // case 'monthName': lowerText = fmtMonthShort(d);
        GanttHeaderLowerKind.MonthName => d.ToString("MMM", CultureInfo.InvariantCulture),
        // case 'yearNum': lowerText = fmtYear(d);
        GanttHeaderLowerKind.YearNum => d.Year.ToString(CultureInfo.InvariantCulture),
        // case 'time6h': case 'time12h': lowerText = `${d.getHours()}:00`;
        GanttHeaderLowerKind.Time6h or GanttHeaderLowerKind.Time12h => $"{d.Hour}:00",
        _ => string.Empty,
    };

    /// <summary>
    /// The upper (grouping) header row's label runs — consecutive date units that
    /// share the same upper-row text collapse into one <see cref="GanttHeaderRun"/>.
    /// Empty upper text (<see cref="GanttHeaderUpperKind.None"/>, i.e.
    /// <see cref="GanttViewMode.Year"/>) never starts a run, mirroring v2's
    /// <c>if (upperText &amp;&amp; upperText !== lastUpperLabel)</c> guard (gantt-v2.js
    /// lines 386-404) — an empty string is falsy in JS and is never emitted.
    /// </summary>
    internal static IReadOnlyList<GanttHeaderRun> UpperRuns(GanttViewMode mode, IReadOnlyList<DateTime> units)
    {
        var cfg = GetConfig(mode);
        var runs = new List<GanttHeaderRun>();
        if (cfg.HeaderUpper == GanttHeaderUpperKind.None) return runs;

        var runStart = -1;
        string? runLabel = null;
        for (var i = 0; i < units.Count; i++)
        {
            var label = UpperLabel(cfg.HeaderUpper, units[i]);
            if (label != runLabel)
            {
                if (runStart >= 0) runs.Add(new GanttHeaderRun(runStart, i - runStart, runLabel!));
                runStart = i;
                runLabel = label;
            }
        }
        if (runStart >= 0) runs.Add(new GanttHeaderRun(runStart, units.Count - runStart, runLabel!));
        return runs;
    }

    private static string UpperLabel(GanttHeaderUpperKind kind, DateTime d) => kind switch
    {
        // case 'month': upperText = fmtMonth(d); -> d.toLocaleString(undefined, { month: 'long' })
        GanttHeaderUpperKind.Month => d.ToString("MMMM", CultureInfo.InvariantCulture),
        // case 'year': upperText = fmtYear(d);
        GanttHeaderUpperKind.Year => d.Year.ToString(CultureInfo.InvariantCulture),
        // case 'day': upperText = `${fmtMonth(d)} ${d.getDate()}`;
        GanttHeaderUpperKind.Day => $"{d.ToString("MMMM", CultureInfo.InvariantCulture)} {d.Day}",
        _ => string.Empty,
    };
}

namespace Lumeo.GanttV3;

/// <summary>
/// A half-open date window describing which portion of the timeline is currently
/// materialized/rendered (design spec "Virtualization" — horizontal windowed time
/// range that extends on scroll). Pure data: no timezone conversion is ever applied
/// to <see cref="Start"/>/<see cref="End"/> anywhere in GanttV3 (see the TZ/DST-safety
/// note on <see cref="GanttScale"/>), so they keep whatever <see cref="DateTimeKind"/>
/// the caller gave them.
/// </summary>
internal readonly record struct GanttDateRange(DateTime Start, DateTime End);

/// <summary>
/// Hoistable Gantt store — the REUI <c>useGanttState</c> analog called out in the
/// design spec ("Public API" &gt; Additive &gt; <c>GanttState</c>: "nav and view can be
/// rendered separately against one shared state instance"). Deliberately a plain C#
/// class with zero Blazor/DI/CascadingValue dependency, so it can be constructed and
/// unit-tested in isolation and so a single instance can later be shared between a
/// separately-rendered <c>GanttNav</c> and <c>GanttTimeline</c> (Phase 2/3) without
/// either owning the other's lifetime.
///
/// <c>internal</c> for now: the phase-1 plan promotes only <see cref="GanttTask.ParentId"/>
/// to the public surface (see PublicAPI.Unshipped.txt) — this type becomes public API
/// once a component actually exposes a <c>State</c> parameter wired to it (Phase 3).
///
/// Every mutator is idempotent with respect to <see cref="Changed"/>: setting a value
/// that is already current is a silent no-op and does not raise the event. This mirrors
/// the Gantt (v2) component's own change-detection discipline (hash-gated re-pushes —
/// see <c>Gantt.razor</c>'s <c>ComputeTasksHash</c>/<c>_lastOptionsHash</c> pattern) so a
/// caller that re-applies the same value on every render (a common Blazor pattern)
/// doesn't spuriously notify subscribers.
/// </summary>
internal sealed class GanttState
{
    private List<GanttTask> _tasks = new();
    private GanttViewMode _viewMode = GanttViewMode.Day;
    private GanttDateRange _visibleRange;
    private readonly HashSet<string> _collapsed = new();

    /// <summary>Raised after any mutator below actually changes state. Not raised for no-op sets (same value re-applied).</summary>
    public event Action? Changed;

    /// <summary>The current task set. Replace via <see cref="SetTasks"/> — this list is never mutated in place.</summary>
    public IReadOnlyList<GanttTask> Tasks => _tasks;

    /// <summary>The active view mode. Change via <see cref="SetViewMode"/>.</summary>
    public GanttViewMode ViewMode => _viewMode;

    /// <summary>The currently materialized date window. Change via <see cref="SetVisibleRange(DateTime,DateTime)"/>.</summary>
    public GanttDateRange VisibleRange => _visibleRange;

    /// <summary>Ids of collapsed (children-hidden) rows. Mutate via <see cref="SetCollapsed"/>/<see cref="ToggleCollapsed"/>.</summary>
    public IReadOnlySet<string> Collapsed => _collapsed;

    /// <summary>
    /// Replaces the task set. No-ops (and does not raise <see cref="Changed"/>) when
    /// the new sequence is value-equal, element-for-element, to the current one —
    /// <see cref="GanttTask"/> is a record, so this is a cheap structural comparison
    /// that also picks up a <see cref="GanttTask.ParentId"/>-only change.
    /// </summary>
    public void SetTasks(IEnumerable<GanttTask> tasks)
    {
        ArgumentNullException.ThrowIfNull(tasks);
        var next = tasks as IReadOnlyList<GanttTask> ?? tasks.ToList();
        if (TasksEqual(_tasks, next)) return;
        _tasks = next as List<GanttTask> ?? next.ToList();
        RaiseChanged();
    }

    /// <summary>Sets the active view mode. No-op when unchanged.</summary>
    public void SetViewMode(GanttViewMode mode)
    {
        if (_viewMode == mode) return;
        _viewMode = mode;
        RaiseChanged();
    }

    /// <summary>Sets the materialized date window. No-op when unchanged.</summary>
    public void SetVisibleRange(DateTime start, DateTime end) => SetVisibleRange(new GanttDateRange(start, end));

    /// <summary>Sets the materialized date window. No-op when unchanged.</summary>
    public void SetVisibleRange(GanttDateRange range)
    {
        if (_visibleRange == range) return;
        _visibleRange = range;
        RaiseChanged();
    }

    /// <summary>True when the given task/row id is currently collapsed.</summary>
    public bool IsCollapsed(string taskId) => _collapsed.Contains(taskId);

    /// <summary>Sets or clears the collapsed state for a task/row id. No-op when unchanged.</summary>
    public void SetCollapsed(string taskId, bool collapsed)
    {
        var changed = collapsed ? _collapsed.Add(taskId) : _collapsed.Remove(taskId);
        if (changed) RaiseChanged();
    }

    /// <summary>Flips the collapsed state for a task/row id. Always raises <see cref="Changed"/> (a toggle is never a no-op).</summary>
    public void ToggleCollapsed(string taskId) => SetCollapsed(taskId, !IsCollapsed(taskId));

    private void RaiseChanged() => Changed?.Invoke();

    private static bool TasksEqual(IReadOnlyList<GanttTask> a, IReadOnlyList<GanttTask> b)
    {
        if (a.Count != b.Count) return false;
        for (var i = 0; i < a.Count; i++)
            if (a[i] != b[i]) return false;
        return true;
    }
}

@namespace Lumeo
@using System.ComponentModel
@using System.Globalization
@using Lumeo.GanttV3
@attribute [EditorBrowsable(EditorBrowsableState.Never)]

@* GanttTimeline — the scrollable header + row canvas (design spec Phase 2, T2
   "read-only markup"). Renders the two-row grouped header from
   GanttScale.BuildHeaderRows-equivalent helpers (UpperRuns/LowerLabels),
   vertical grid column lines, the today marker, and one GanttBar per task via
   a vertical Virtualize<T>.

   Deliberately takes Tasks/ViewMode/RangeStart/RangeEnd as plain parameters
   instead of a GanttState reference: GanttState is still `internal` (Phase-3
   promotion, per its own remarks — "becomes public API once a component
   actually exposes a State parameter wired to it"), and this component's
   generated partial class is unavoidably `public` (the Razor compiler always
   emits an explicit `public` modifier for component classes — there is no
   supported directive to change it; see dotnet/aspnetcore#5516 and
   dotnet/razor#8715, both open feature requests). A public `GanttState State`
   parameter would either force GanttState public too (jumping the gun on
   Phase 3) or fail to compile (CS0053, a public member can't expose a
   less-accessible type) — so Gantt3 (the shared-state owner) unpacks its
   GanttState into these primitives instead.

   [EditorBrowsable(Never)] keeps this working-name API out of consumer
   IntelliSense until the Phase-4 rename (fix-round follow-up). *@
<div class="@RootClass" @attributes="AdditionalAttributes">
    <div class="relative" style="@CanvasStyle">
        @* Two-row header — sticky so it stays visible while the row canvas scrolls vertically. *@
        <div class="lumeo-gantt-v3-header sticky top-0 z-10 border-b border-border/60 bg-card" style="@HeaderStyle">
            <div class="relative" style="height:20px;">
                @foreach (var run in UpperRuns)
                {
                    <div class="absolute truncate text-xs font-semibold text-foreground" style="@UpperRunStyle(run)">@run.Label</div>
                }
            </div>
            <div class="relative flex" style="height:@((GanttScale.HeaderHeight - 20).ToString(CultureInfo.InvariantCulture))px;">
                @for (var i = 0; i < Units.Count; i++)
                {
                    var label = LowerLabels[i];
                    <div class="shrink-0 text-center text-xs text-muted-foreground" style="@ColumnCellStyle">@label</div>
                }
            </div>
        </div>

        @* Vertical grid lines, spanning the full row canvas height below the header. *@
        <div class="pointer-events-none absolute inset-x-0" style="@GridLinesContainerStyle">
            @for (var i = 0; i <= Units.Count; i++)
            {
                <div class="absolute inset-y-0 border-s border-border/40" style="@GridLineStyle(i)"></div>
            }
        </div>

        @if (TodayInRange)
        {
            <div class="lumeo-gantt-v3-today-line pointer-events-none absolute inset-y-0 border-s border-primary opacity-60" style="@TodayLineStyle"></div>
        }

        @* Row canvas. *@
        <div class="relative" style="@RowsContainerStyle">
            <Virtualize Items="@RowItems" Context="row" ItemSize="@((float)GanttScale.RowHeight)">
                @if (row.Task is not null)
                {
                    <GanttBar Task="row.Task" X="row.X" Width="row.Width" RowIndex="row.RowIndex"
                              BarHeight="EffectiveBarHeight" Color="@row.Color" BarTemplate="BarTemplate" />
                }
            </Virtualize>
        </div>

        @* Dependency-arrow overlay — see GanttArrowLayer's own remarks for why it
           recomputes geometry independently from the same EffectiveRows/GanttScale
           inputs rather than reaching into this component's RowItems. *@
        <GanttArrowLayer Rows="@EffectiveRows" ViewMode="@ViewMode" Origin="@Origin"
                         ColumnWidth="@EffectiveColumnWidth" BarHeight="@EffectiveBarHeight"
                         Width="@TotalWidth" Height="@CanvasHeight" />
    </div>
</div>

@code {
    /// <summary>The tasks (and milestones) rendered as bars, in display order. Ignored when <see cref="Rows"/> is set.</summary>
    [Parameter] public IReadOnlyList<GanttTask> Tasks { get; set; } = Array.Empty<GanttTask>();

    /// <summary>
    /// The already-flattened, collapse-filtered row list (design spec Phase 2,
    /// T3's tree-pane/hierarchy row model — see <c>GanttRowModel</c>) — the same
    /// list a sibling <c>GanttTree</c> renders against, so both panes stay
    /// row-for-row aligned. When set, this takes priority over <see cref="Tasks"/>
    /// (which may still include header-hidden/collapsed tasks the caller never
    /// meant to show). When null (T2's original contract, still exercised by
    /// callers with no grouping/hierarchy), each entry of <see cref="Tasks"/>
    /// becomes its own row, 1:1, in list order — unchanged from T2's behavior.
    /// </summary>
    [Parameter] public IReadOnlyList<GanttVisibleRow>? Rows { get; set; }

    /// <summary>The active zoom level — determines column width/unit/header format via <see cref="GanttScale"/>.</summary>
    [Parameter] public GanttViewMode ViewMode { get; set; } = GanttViewMode.Day;

    /// <summary>The materialized date window's start (inclusive).</summary>
    [Parameter] public DateTime RangeStart { get; set; }

    /// <summary>The materialized date window's end (inclusive).</summary>
    [Parameter] public DateTime RangeEnd { get; set; }

    /// <summary>Override the pixel height of each task bar. Defaults to <see cref="GanttScale.DefaultBarHeight"/>.</summary>
    [Parameter] public int? BarHeight { get; set; }

    /// <summary>Override the pixel width of each date column for the current view mode.</summary>
    [Parameter] public int? ColumnWidth { get; set; }

    /// <summary>Highlight today with a vertical marker line. Default true.</summary>
    [Parameter] public bool TodayHighlight { get; set; } = true;

    /// <summary>Per-task bar colour override — see <c>Lumeo.Gantt</c>'s v2 <c>Gantt.BarColor</c> for the contract.</summary>
    [Parameter] public Func<GanttTask, string?>? BarColor { get; set; }

    /// <summary>Replaces a bar's default label content when set.</summary>
    [Parameter] public RenderFragment<GanttTask>? BarTemplate { get; set; }

    /// <summary>Additional CSS classes merged onto the root scroll container.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures unmatched attributes and applies them to the root scroll container.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass => Cx.Merge("relative w-full overflow-auto", Class);

    private GanttScaleConfig Cfg => GanttScale.GetConfig(ViewMode);
    private int EffectiveColumnWidth => ColumnWidth ?? Cfg.ColumnWidth;
    private int EffectiveBarHeight => BarHeight ?? GanttScale.DefaultBarHeight;

    private IReadOnlyList<DateTime> Units => GanttScale.BuildDateUnits(ViewMode, RangeStart, RangeEnd);
    private DateTime Origin => Units.Count > 0 ? Units[0] : RangeStart;
    private double TotalWidth => Units.Count * (double)EffectiveColumnWidth;

    // Falls back to a 1:1 Task-per-row list (T2's original contract) when the
    // caller doesn't supply a pre-flattened Rows list — see the Rows parameter's
    // remarks. Every entry is a GanttRowKind.Task row at depth 0 with no
    // collapse/toggle affordance, matching what T2 always rendered.
    private IReadOnlyList<GanttVisibleRow> EffectiveRows => Rows ?? BuildFallbackRows();

    private List<GanttVisibleRow> BuildFallbackRows()
    {
        var rows = new List<GanttVisibleRow>(Tasks.Count);
        foreach (var task in Tasks)
            rows.Add(new GanttVisibleRow(GanttRowKind.Task, task, task.Name, 0, false, null, false));
        return rows;
    }

    private double CanvasHeight => GanttScale.HeaderHeight + Math.Max(1, EffectiveRows.Count) * GanttScale.RowHeight;

    private IReadOnlyList<GanttHeaderRun> UpperRuns => GanttScale.UpperRuns(ViewMode, Units);
    private IReadOnlyList<string> LowerLabels => GanttScale.LowerLabels(ViewMode, Units);

    private double TodayX => GanttScale.DateToPixel(ViewMode, Origin, DateTime.Today);
    private bool TodayInRange => TodayHighlight && Units.Count > 0 && TodayX >= 0 && TodayX <= TotalWidth;

    private string CanvasStyle => FormattableString.Invariant($"width:{TotalWidth}px;min-height:{CanvasHeight}px;");
    private string HeaderStyle => FormattableString.Invariant($"height:{GanttScale.HeaderHeight}px;width:{TotalWidth}px;");
    private string ColumnCellStyle => FormattableString.Invariant($"width:{EffectiveColumnWidth}px;");

    private string UpperRunStyle(GanttHeaderRun run) =>
        FormattableString.Invariant($"left:{run.StartIndex * EffectiveColumnWidth}px;top:2px;padding-inline-start:8px;");

    private string GridLinesContainerStyle =>
        FormattableString.Invariant($"top:{GanttScale.HeaderHeight}px;bottom:0;");

    private string GridLineStyle(int columnIndex) =>
        FormattableString.Invariant($"left:{columnIndex * EffectiveColumnWidth}px;");

    private string TodayLineStyle =>
        FormattableString.Invariant($"left:{TodayX}px;top:{GanttScale.HeaderHeight - 4}px;");

    private string RowsContainerStyle =>
        FormattableString.Invariant($"height:{Math.Max(1, EffectiveRows.Count) * GanttScale.RowHeight}px;width:{TotalWidth}px;");

    // One row slot's already-resolved geometry, computed fresh from GanttScale
    // each render — see GanttScale.BarGeometry for the underlying math (a 1:1
    // port of gantt-v2.js's dateToX usage: render() lines 508-512 for a regular
    // bar, lines 459-463 for a milestone's diamond center). Task is null for a
    // GanttRowKind.GroupHeader slot — Virtualize still allocates it a slot (so
    // RowIndex stays list-position-aligned for every OTHER row, which its
    // internal viewport math depends on), but no <GanttBar> renders for it
    // (see the @if (row.Task is not null) guard in the markup above).
    internal sealed record GanttTimelineRow(GanttTask? Task, double X, double Width, int RowIndex, string? Color);

    // Virtualize<TItem>.Items requires ICollection<TItem> (IReadOnlyList doesn't
    // implement it) — List<T> both satisfies that and matches the pattern
    // DataGridBody uses for its own Virtualize Items source (_indexedItems).
    private List<GanttTimelineRow> RowItems
    {
        get
        {
            var visibleRows = EffectiveRows;
            var rows = new List<GanttTimelineRow>(visibleRows.Count);
            for (var i = 0; i < visibleRows.Count; i++)
            {
                var task = visibleRows[i].Task;
                if (task is null)
                {
                    // Group-header slot: still occupies row index i (matching v2's
                    // rowSlot, which advances for header rows too), but has no bar.
                    rows.Add(new GanttTimelineRow(null, 0, 0, i, null));
                    continue;
                }
                var color = BarColor?.Invoke(task);
                var (x, width) = GanttScale.BarGeometry(task, ViewMode, Origin, EffectiveColumnWidth, EffectiveBarHeight);
                rows.Add(new GanttTimelineRow(task, x, width, i, color));
            }
            return rows;
        }
    }
}

@namespace Lumeo
@using System.ComponentModel
@using Lumeo.GanttV3
@attribute [EditorBrowsable(EditorBrowsableState.Never)]

@* GanttTree — v3's left tree/list pane (design spec Phase 2, T3): one row per
   entry in Rows, the IDENTICAL row list GanttTimeline renders bars against
   (see GanttRowModel), so the two panes always align — same GanttScale.RowHeight
   per row, same order, same collapse-filtered visibility. Renders the task
   name (or, for a flat-grouping GanttRowKind.GroupHeader row, the group's
   label) indented per Depth, with a chevron toggle on any collapsible row
   (a hierarchy parent, or a group header).

   Purely presentational, same contract as GanttNav: every interaction
   bubbles up via OnToggleCollapse into whatever owns GanttState (Gantt3) —
   this component never touches GanttState itself. The leading spacer div
   matches GanttTimeline's two-row header height so the two panes' row
   canvases start at the same Y (Phase 2's "one shared scroll container"
   design — see Gantt3's remarks — relies on this alignment, not on any
   scroll-sync JS).

   NOTE (accessibility): see GanttBar.razor's NOTE — the Razor compiler always
   generates a component's class as `public`, so despite the task spec asking
   for `internal`, this stays `public` and its new members are recorded in
   PublicAPI.Unshipped.txt; flagged for the reviewer/team lead to confirm.
   [EditorBrowsable(Never)] keeps this working-name API out of consumer
   IntelliSense until the Phase-4 rename (fix-round follow-up). *@
<div class="@RootClass" @attributes="AdditionalAttributes">
    <div style="@HeaderSpacerStyle"></div>
    @foreach (var row in Rows)
    {
        <div class="@RowClass(row)" style="@RowStyle" data-row-kind="@(row.Kind == GanttRowKind.GroupHeader ? "group" : "task")">
            <span class="lumeo-gantt-v3-tree-indent shrink-0" style="@IndentStyle(row)"></span>
            @if (row.ToggleKey is not null)
            {
                <button type="button"
                        class="lumeo-gantt-v3-tree-toggle inline-flex h-4 w-4 shrink-0 items-center justify-center"
                        aria-expanded="@((!row.IsCollapsed).ToString().ToLower())"
                        @onclick="() => HandleToggleAsync(row.ToggleKey)">
                    <SvgGlyph Svg="@(row.IsCollapsed ? LumeoIcons.ChevronRight : LumeoIcons.ChevronDown)" class="h-3.5 w-3.5" />
                </button>
            }
            else
            {
                <span class="lumeo-gantt-v3-tree-toggle-spacer inline-block h-4 w-4 shrink-0"></span>
            }
            <span class="lumeo-gantt-v3-tree-label truncate text-sm">@row.Label</span>
        </div>
    }
</div>

@code {
    /// <summary>The visible row list — identical to what's fed to GanttTimeline/GanttArrowLayer (design spec: single source of truth for row order/visibility).</summary>
    [Parameter] public IReadOnlyList<GanttVisibleRow> Rows { get; set; } = Array.Empty<GanttVisibleRow>();

    /// <summary>Raised with a row's <see cref="GanttVisibleRow.ToggleKey"/> when its chevron is clicked. The owner (Gantt3) applies it via <c>GanttState.ToggleCollapsed</c>.</summary>
    [Parameter] public EventCallback<string> OnToggleCollapse { get; set; }

    /// <summary>Additional CSS classes merged onto the root pane element.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>Captures unmatched attributes and applies them to the root pane element.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string RootClass => Cx.Merge("relative w-56 shrink-0 border-e border-border/60 bg-card", Class);

    private string HeaderSpacerStyle => FormattableString.Invariant($"height:{GanttScale.HeaderHeight}px;");

